    var expectedId = $"retro-{DateTimeOffset.UtcNow:yyyy-MM-dd}-{topic}";

    var result = await engram.ReflectAsync(text: lessonText, ns: ns, topic: topic, ct: ct);

    // status is "stored" or "duplicate_warning"
