        //   - skip silently (default — the build already had a similar lesson today).
        var existingId = ExtractExistingId(result.Message);
        return new ReflectOutcome(expectedId, result.Status, Stored: false, existingId);
    }

    // Verify by ID — get_memory does not count as an access
    var verify = await engram.GetMemoryAsync(expectedId, ct);
    if (verify is null)
        throw new InvalidOperationException($"reflect reported stored but {expectedId} not found");

    // Sanity: should be ltm + lesson
    if (verify.LifecycleState != "ltm" || verify.Category != "lesson")
        throw new InvalidOperationException($"unexpected state: {verify.LifecycleState}/{verify.Category}");

    return new ReflectOutcome(expectedId, result.Status, Stored: true, ExistingId: null);
}

private static string? ExtractExistingId(string msg)
{
    // Message format: "Very similar reflection already exists: '<id>' (score: 0.xxx)..."
    var m = System.Text.RegularExpressions.Regex.Match(msg, @"exists: '([^']+)'");
    return m.Success ? m.Groups[1].Value : null;
}
